module non_maximum_suppression(  
    input [7:0] pixel_value,  
    input [7:0] neighbor1,  
    input [7:0] neighbor2,  
    output reg edge_detected  
);  
    always @(*) begin  
        if (pixel_value > neighbor1 && pixel_value > neighbor2)  
            edge_detected = 1'b1;  
        else  
            edge_detected = 1'b0;  
    end  
endmodule
